 NULL AS SECQUA6_CF, NULL AS SECQUA7_CF, NULL AS SECQUA8_CF, NULL AS SECQUA9_CF, TFAMLIA.SIGSHA_R AS SIGSHA_R, TSECTION_DEL.SOB_CF AS SOB_CF, TCLINTSU_CED.SORDNBR_NT AS 
 SORDNBR_NT, TCLSTABI_CED.SPCURRAT_CT AS SPCURRAT_CT, RIGHT (REPLICATE ("0", 2) + CONVERT (VARCHAR, TSECTION_DEL.ssd_cf), 2) + "-" + RIGHT (REPLICATE ("0", 2) + 
 CONVERT (VARCHAR, TSECTION_DEL.accesb_cf), 2) AS SSD_ESB, 0 AS STOCNDEXI_B, TSECTION_DEL.SUBNAT_CF AS SUBNAT_CF, CASE WHEN TSECTION_DEL.LOB_CF IN ("30", "31") 
 THEN "L" ELSE "F" END AS TFL_IND, NULL AS EDI_CALC, NULL AS CAT_RISK_COVERED_CALC, CASE WHEN TSECTION_DEL.CTR_NF IS NOT NULL AND TSECTION_DEL.CTR_NF <> "        
 " THEN CASE WHEN TSECTION_DEL.FACADMTYP_B = 0 THEN "BS" ELSE "Specialties" END ELSE NULL END AS SBS_ADMIN_CALC, ISNULL (TACCLIA.MPLSCEAMT_M, 0) + 
 ISNULL (TACCLIA.OTHPARAMT_M, 0) AS GAL_CONSO_CALC, TACCLIA.ACCLIA_M - ISNULL (TACCLIA.CBIAMT_M, 0) AS GAL_RETRO_CALC, TFAMLIA.CUTSHA_R * TFAMLIA.RIDSHA_R * 100 AS 
 SCOR_SHARE_ORG_CALC, ISNULL (TACCLIA.CBIAMT_M, 0) AS GAL_CBI_CALC, ISNULL (TACCLIA.JVTAMT_M, 0) AS GAL_JV_CALC, ISNULL (TACCLIA.MPLSCEAMT_M, 0) AS GAL_FAC_IMPACT_CALC, 
 ISNULL (TACCLIA.NGHAMT_M, 0) AS GAL_NEIGHBORHOOD_CALC, ISNULL (TACCLIA.OTHLOBAMT_M, 0) AS GAL_OTHER_LOB_CALC, ISNULL (TACCLIA.OTHPARAMT_M, 0) AS GAL_OTHER_PART_CALC, 
 TFAMLIA.CUTSHA_R * 100 AS SCOR_SHARE_CEDED_CALC, 0 AS SEC_RETRO_RATIO_CALC, TFAMLIA.RIDSHA_R * 100 AS CEDED_SHARE_CALC, 0 AS IO_CLIENT_SCOR_CALC, 
 TFAMCHG.CTBGENFEE_R * 100 AS COM_PC_EXPENSES_CALC, TFAMCHG.FIXCOM_R * 100 AS COM_FIX_CALC, TFAMCHG.LOSCTB_R * 100 AS COM_PC_LOSS_CALC, TFAMCHG.MAXCOM_R * 100 AS 
 COM_VARIABLE_MAX_CALC, TFAMCHG.MAXRATCLP_R * 100 AS LR_VARIABLE_MAX_CALC, TFAMCHG.MINCOM_R * 100 AS COM_VARIABLE_MIN_CALC, TFAMCHG.MINRATCLP_R * 100 AS LR_VARIABLE_MIN_CALC, 
 TFAMCHG.OVRCOM_R * 100 AS COM_OVERRIDER_CALC, TFAMCHG.PRFCOM_R * 100 AS COM_PC_PROFIT_CALC, TFAMCHG.PRVCOM_R * 100 AS COM_VARIABLE_PROV_CALC, NULL AS COM_VARIABLE_CALC, 
 TFAMLIA.LIAAGRDED_M AS AGG_DEDUCTIBLE_CALC, TSECTION_DEL.TOP_CF AS TOP_CF, CASE WHEN TRFCROSSREF.TRFACCSTS_CT IN ( 51, 98, 141, 61 ) AND TRFCROSSREF.TRFSTS_CT <> 14 THEN 1 
 ELSE 0 END AS TRFTRT_B, CASE WHEN TSECTION_DEL.REITYP_CF = 1 THEN 1 ELSE CASE WHEN TSECTION_DEL.REITYP_CF IN ( NULL, 2, 3, 4, 5, 7, 10, 12 ) THEN 2 ELSE CASE WHEN 
 TSECTION_DEL.REITYP_CF = 6 THEN 3 ELSE CASE WHEN TSECTION_DEL.REITYP_CF = 8 THEN 4 ELSE CASE WHEN TSECTION_DEL.REITYP_CF = 9 THEN 5 ELSE CASE WHEN TSECTION_DEL.REITYP_CF = 15 
 THEN 6 ELSE CASE WHEN TSECTION_DEL.REITYP_CF = 16 THEN 7 ELSE CASE WHEN TSECTION_DEL.REITYP_CF = 17 THEN 8 ELSE CASE WHEN TSECTION_DEL.REITYP_CF = 18 THEN 9 ELSE CASE WHEN 
