 NULL AS USRCRTCOD_CT, NULL AS USRCRTVAL_LM, TSECTION_DEL.UWGRP_CF AS UWGRP_CF, TSECTION_DEL.UWORG_CF AS UWORG_CF, NULL AS WRKCAT_CT, TCLIADDR_CED.CLIADDSTA_CF AS CLIADDSTA_CF, 
 TCONTR.PCPSOB_CF AS PCPSOB_CF, TCLIENT_CED.HORDNBR_NT AS HORDNBR_NT, TCLIADDR_IND.CLIADDCTY_CF AS INDADDCTY_CF, TDIVISIO.PCPRSKTRY_CF AS PCPRSKTRY_DIV_CF, TCONTR.PCPOCC_CF AS 
