 END as MANRET_B, 0 as STREXP_B, 0 as FLDEXP_B, 1 as FACADMTYP_B FROM BFAC..TSECTION_DEL TSECTION_DEL LEFT JOIN BFAC..TCONTR TCONTR ON TSECTION_DEL.CTR_NF = TCONTR.CTR_NF AND 
 TSECTION_DEL.UWY_NF = TCONTR.UWY_NF AND TSECTION_DEL.UW_NT = TCONTR.UW_NT AND TSECTION_DEL.END_NT = TCONTR.END_NT INNER JOIN BREF..TSUBSID TSUBSID ON TSUBSID.SSD_CF = 
 TSECTION_DEL.SSD_CF LEFT JOIN BFAC..TDIVISIO TDIVISIO ON TDIVISIO.CTR_NF = TSECTION_DEL.CTR_NF AND TDIVISIO.UWY_NF = TSECTION_DEL.UWY_NF AND TDIVISIO.UW_NT = TSECTION_DEL.UW_NT 
 AND TDIVISIO.END_NT = TSECTION_DEL.END_NT AND TDIVISIO.DIV_NT = TSECTION_DEL.DIV_NT LEFT JOIN BFAC..TACCLIA TACCLIA ON TSECTION_DEL.CTR_NF = TACCLIA.CTR_NF AND 
