 TSECTION_DEL.CTR_NF AND TFAMLIA.UWY_NF = TSECTION_DEL.UWY_NF AND TFAMLIA.UW_NT = TSECTION_DEL.UW_NT AND TFAMLIA.END_NT = TSECTION_DEL.END_NT AND TFAMLIA.SEC_NF = 
