 TCLIENT_CED.CLI_NF LEFT OUTER JOIN BCLI..TCLSTABI TCLSTABI_CED ON TSECTION_DEL.CED_NF = TCLSTABI_CED.CLI_NF LEFT OUTER JOIN BCLI..TCLINTSU TCLINTSU_CED ON (TCLIENT_CED.CLI_NF = 
