 TCLIENT_IND.HINDNBR_NT END = TREPCRI_IND.HORDNBR_NT AND TREPCRI_IND.LAG_CF = "E" LEFT OUTER JOIN BCLI..TCLIADDR TCLIADDR_IND ON (TCLIADDR_IND.CLI_NF = TCLIENT_IND.CLI_NF AND 
 TCLIADDR_IND.ADDSUP_B = 0 AND TCLIADDR_IND.HEDOFFIND_B = 1) LEFT OUTER JOIN BREF..TOCC TOCC ON TSECTION_DEL.OCC_CF = TOCC.RSKNAT_CF LEFT OUTER JOIN BREF..TSOBBLOB TSOBBLOB ON 
