 CASE WHEN TCONTR.CTR_NF is not null and TCONTR.CTR_NF <> "        " THEN CASE WHEN TCONTR.FACADMTYP_B = 0 THEN "BS" ELSE "Specialties" END ELSE null END as SBS_ADMIN_CALC,
 null as GAL_CONSO_CALC, null as GAL_RETRO_CALC, TFAMLIA.CUTSHA_R * TFAMLIA.RIDSHA_R * 100 as SCOR_SHARE_ORG_CALC, null as GAL_CBI_CALC, null as GAL_JV_CALC, null as 
 GAL_FAC_IMPACT_CALC, null as GAL_NEIGHBORHOOD_CALC, null as GAL_OTHER_LOB_CALC, null as GAL_OTHER_PART_CALC, TFAMLIA.CUTSHA_R * 100 as SCOR_SHARE_CEDED_CALC, 
 TSECTION.RETPCT_R*100 as SEC_RETRO_RATIO_CALC, TFAMLIA.RIDSHA_R * 100 as CEDED_SHARE_CALC, CASE WHEN TCONTR.CED_NF <> 0 THEN 1 ELSE 0 END as IO_CLIENT_SCOR_CALC, 
 TFAMCHG.CTBGENFEE_R * 100 as COM_PC_EXPENSES_CALC, TFAMCHG.FIXCOM_R * 100 as COM_FIX_CALC, TFAMCHG.LOSCTB_R * 100 as COM_PC_LOSS_CALC, TFAMCHG.MAXCOM_R * 100 as 
