 THEN 4 ELSE CASE WHEN TCONTR.REITYP_CF = 9 THEN 5 ELSE CASE WHEN TCONTR.REITYP_CF = 15 THEN 6 ELSE CASE WHEN TCONTR.REITYP_CF = 16 THEN 7 ELSE CASE WHEN TCONTR.REITYP_CF = 17 
