 NULL AS INDADDCTY_CF, NULL AS PCPRSKTRY_DIV_CF, TCONTR.PCPOCC_CF AS PCPOCC_CF, TCONTR.POLDUR_CF AS POLDUR_CF, THOLDING_CED.ULT_NF AS CEDULT_NF, NULL AS MAS_NF, 
 (case when TSECTION.PCPTER_B = 1 then TSECTION.PCPRSKTRY_CF else null end) as PRINCRSKTRY_CF, TCONTR.MANRET_B as MANRET_B, TSECTION.STREXP_B as STREXP_B, 
 TSECTION.FLDEXP_B as FLDEXP_B, TCONTR.FACADMTYP_B as FACADMTYP_B FROM BTRT..TCONTR TCONTR INNER JOIN BREF..TSUBSID TSUBSID ON TSUBSID.SSD_CF = TCONTR.SSD_CF LEFT JOIN 
