 TSECTION.SEC_NF LEFT OUTER JOIN BTRT..TFAMLIA TFAMLIA ON TFAMLIA.CTR_NF = TCONTR.CTR_NF AND TFAMLIA.UWY_NF = TCONTR.UWY_NF AND TFAMLIA.UW_NT = TCONTR.UW_NT AND TFAMLIA.END_NT = 
 TCONTR.END_NT AND TFAMLIA.SEC_NF = TSECTION.SEC_NF LEFT OUTER JOIN BTRT..TFAMCHG TFAMCHG ON TFAMCHG.CTR_NF = TCONTR.CTR_NF AND TFAMCHG.UWY_NF = TCONTR.UWY_NF AND TFAMCHG.UW_NT = 
 TCONTR.UW_NT AND TFAMCHG.END_NT = TCONTR.END_NT AND TFAMCHG.SEC_NF = TSECTION.SEC_NF LEFT OUTER JOIN BTRT..TFAMCAT TFAMCAT ON TFAMCAT.CTR_NF = TCONTR.CTR_NF AND TFAMCAT.UWY_NF = 
 TCONTR.UWY_NF AND TFAMCAT.UW_NT = TCONTR.UW_NT AND TFAMCAT.END_NT = TCONTR.END_NT AND TFAMCAT.SEC_NF = TSECTION.SEC_NF LEFT OUTER JOIN BCLI..TCLIENT TCLIENT_CED ON TCONTR.CED_NF =
 TCLIENT_CED.CLI_NF LEFT OUTER JOIN BCLI..THOLDING THOLDING_CED ON TCLIENT_CED.HLD_NF = THOLDING_CED.HLD_NF LEFT OUTER JOIN BCLI..TCLSTABI TCLSTABI_CED ON TCONTR.CED_NF = 
 TCLSTABI_CED.CLI_NF LEFT OUTER JOIN BCLI..TCLINTSU TCLINTSU_CED ON (TCLIENT_CED.CLI_NF = TCLINTSU_CED.CLI_NF AND TCLINTSU_CED.SORDNBR_NT is not null AND 
 TCLINTSU_CED.CLIINTSSD_CF <> 3) LEFT OUTER JOIN BCLI..TCLIENT TCLIENT_PAY ON TCONTR.GENPRMPAY_NF = TCLIENT_PAY.CLI_NF LEFT OUTER JOIN BTRT..TRFCROSSREF TRFCROSSREF ON 
 (TRFCROSSREF.CTR_NF = TCONTR.CTR_NF and TRFCROSSREF.TRFACCSTS_CT in (51,98,141,61) and TRFCROSSREF.TRFSTS_CT <> 14 ) LEFT OUTER JOIN BCLI..TCLIADDR TCLIADDR_CED ON 
 (TCONTR.CED_NF = TCLIADDR_CED.CLI_NF AND TCLIADDR_CED.ADDSUP_B=0 AND TCLIADDR_CED.HEDOFFIND_B=1) LEFT JOIN BREF..TGRP2 TGRP2 on TCONTR.UWGRP_CF = TGRP2.GRP_CF WHERE 
 TSUBSID.PRDSIT_CF = @prdsitCf'
where SGTUWTAB_CF = 'TSEGUWASMSEC'

